#!/usr/bin/env python3\nimport re, sys, json\ntext = sys.stdin.read()\nrsi = re.search(r'RSI[\\s:]+(\\d+\\.\\d+)', text)\nvol = re.search(r'volume_ratio[\\s:]+(\\d+\\.\\d+)', text)\nstatus = re.search(r'rsi_status[\\s:]+\"([^\"]+)\"', text)\nprint(json.dumps({'rsi': rsi.group(1) if rsi else None, 'vol': vol.group(1) if vol else None, 'rsi_status': status.group(1) if status else None}))